if (f('Q3VC5').any('88','99'))
	{
       if (f('Q3VC5')!='1')
       {
          f('TextQ4').set(1); 
            SetRespondentValue('ResumePoint',2)
          //RedirectToRespondentUrl("Q4");
       }
	}

else
{
  if (f('Q3VC5')=='1')
    {
        var NumCheck = f('Q3VC5_1_Other').toNumber();

      if(f('Q3VC5_1_Other')=='' )
      {
            RaiseError();
            SetQuestionErrorMessage(LangIDs.en,"Answer should not be Empty.");   
            SetQuestionErrorMessage(LangIDs.es_es,"Answer should not be Empty.");

      }

      else { 

        if(!isNaN(NumCheck) )
            {
            if (NumCheck == 0)
                {

                f('TextQ4').set(1); 
                  SetRespondentValue('ResumePoint',2)
                //RedirectToRespondentUrl("Q4");
                  //return;	
                }
            else if (NumCheck >=1 && NumCheck <=87 && (NumCheck !=0))
                {
                    if (NumCheck ==1)
                        {
                            f('TextQ4').set(1); 
                        }
                    else 
                        {
                            f('TextQ4').set(2); 
                        }
                  SetRespondentValue('ResumePoint',2)
                //RedirectToRespondentUrl("Q4");
                  //return;	
                }
            else 
                {
                    RaiseError();
                    SetQuestionErrorMessage(LangIDs.en,"Answer is not in range '00 - 87'.");
                   SetQuestionErrorMessage(LangIDs.es_es,"Answer is not in range '00 - 87'.");
                }
            }
            else
                {
                    RaiseError();
                    SetQuestionErrorMessage(LangIDs.en,"Answer is not a numeric."); 
                    SetQuestionErrorMessage(LangIDs.es_es,"Answer is not a numeric.");
                }
           }
    }
}

