function DisplayCallHistory()
{
var tries:int=GetCallAttemptCount();

var start:int=1;

if (tries > 10)
{
start=tries-10;
}

if (tries > 1)
{
var string = "";
string += "<table border=2>";
string += "<tr>";
string += "<td>Call ID</td>";
string += "<td>Last Call Date/Time</td>";
string += "<td>Ivr</td>";
string += "<td>Call Outcome</td>";
string += "<td>App Date/Time</td>";
string += "<td>Contact Name</td>";
string += "<td>Comments</td>";
string += "</tr>";

for(var i=start;i<(tries-1);i++) 
{
var dateAll : String = f('CallDateTime',i).get();
var DateArray : Array = dateAll.split(" ");
var DateFmt : String = DateArray[0] + " "+DateArray[1] +" "+DateArray[2]+" "+DateArray[3];



//var datetime=f('CallDateTime',i).toBoolean() ? f('CallDateTime',i).get() : "&nbsp;";
var datetime=DateFmt != null ? DateFmt : "&nbsp;";


var interviewer=f('Inter_Name',i).toBoolean() ? f('Inter_Name',i).get() : "&nbsp;";
//var interviewer=f('IVRCH',i).toBoolean() ? f('IVRCH',i).get() : "&nbsp;";
//var interviewer=f('IVRCH',i).toBoolean() ? f('IVRCH',i).get() : "&nbsp;";
var its=f('CallExtendedStatus',i).toBoolean() ? f('CallExtendedStatus',i).valueLabel() : "&nbsp;";

var AppAll : String = f('CallAppTime',i).get();
var ADateArray : Array = AppAll.split(" ");
var ADateFmt : String = ADateArray[0] + " "+ADateArray[1] +" "+ADateArray[2]+" "+ADateArray[3];
var apptime=f('CallAppTime',i).toBoolean() ? ADateFmt : "&nbsp;";

var contactperson=f('Contactperson',i).toBoolean() ? f('Contactperson',i).get() : "&nbsp;";
var comments=f('CallComments',i).toBoolean() ? f('CallComments',i).get() : "&nbsp;" + "</td>";

string += "<tr>";
string += "<td>" +i+"</td>";
string += "<td>" +datetime+"</td>";
string += "<td>" +interviewer+ "</td>";
string += "<td>" +its+ "</td>";
string += "<td>" +apptime+"</td>";
string += "<td>" +contactperson+ "</td>";
string += "<td>" +comments+ "</td>";
string += "</tr>";
}
string += "</table>";
}
return string;
}

